#!/usr/bin/env python3
"""
금융 자산 관리 앱 — 자동 설치 스크립트
실행: python setup.py
"""
import base64, os, json, sqlite3

DATA = '{"files": {"app.py": "", "database.py": "", "requirements.txt": "Zmxhc2s+PTMuMC4wCmZsYXNrLWNvcnM+PTQuMC4wCg==", "templates/base.html": "", "templates/dashboard.html": "", "templates/income.html": "", "templates/budget.html": "", "templates/cards.html": "", "templates/investments.html": "", "templates/realestate.html": "", "templates/loans.html": "", "templates/pension.html": "", "templates/goals.html": "", "templates/monthly.html": "", "static/css/style.css": "", "static/js/common.js": "", "static/js/dashboard.js": ""}, "db_sql": ""}'

def main():
    data   = json.loads(DATA)
    here   = os.path.dirname(os.path.abspath(__file__))

    # 파일 복원
    for rel, b64 in data['files'].items():
        dest = os.path.join(here, rel.replace('/', os.sep))
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, 'wb') as f:
            f.write(base64.b64decode(b64))
        print(f'  생성: {rel}')

    # DB 복원
    db_path = os.path.join(here, 'finance.db')
    if os.path.exists(db_path):
        ans = input('\nfinance.db 가 이미 있습니다. 덮어쓸까요? (y/N): ')
        if ans.strip().lower() != 'y':
            print('DB 복원 건너뜀.')
            db_path = None
    if db_path:
        sql = base64.b64decode(data['db_sql']).decode('utf-8')
        conn = sqlite3.connect(db_path)
        conn.executescript(sql)
        conn.close()
        print('  생성: finance.db')

    print("""
==============================================
설치 완료!

다음 명령어로 실행하세요:
  pip install -r requirements.txt
  python app.py

브라우저에서 http://localhost:5000 접속
==============================================
""")

if __name__ == '__main__':
    main()